import scala.collection.mutable.PriorityQueue

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
  val directions = Array((0, 1), (1, 0))
  val pq = PriorityQueue[(Long, Long, Long, Long)]()
  pq.enqueue((1, 0, 0, 0))
  val visited = Array.ofDim[Long](m.toInt, n.toInt)
  visited(0)(0) = 1

  while (pq.nonEmpty) {
    val (cost, time, row, col) = pq.dequeue()
    if (row == m - 1 && col == n - 1) return cost
    if (cost > visited(row)(col)) continue
    if (time % 2 == 1) {
      for ((dr, dc) <- directions) {
        val newRow = row + dr
        val newCol = col + dc
        if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
          val newCost = cost + (newRow + 1) * (newCol + 1)
          if (newCost < visited(newRow)(newCol)) {
            visited(newRow)(newCol) = newCost
            pq.enqueue((newCost, time + 1, newRow, newCol))
          }
        }
      }
    } else {
      val newCost = cost + waitCost(row)(col)
      if (newCost < visited(row)(col)) {
        visited(row)(col) = newCost
        pq.enqueue((newCost, time + 1, row, col))
      }
    }
  }
  -1
}
